clear(); close all;
%[text] ## Parameters
% parameters
numUsr = 1;
numSym = 64;
sampleRate = 122.88e6;
symbolRate = 3.84e6;
osf = sampleRate / symbolRate;
carrierFreq = 18e9;
wavelen = 299792458 / carrierFreq;
rng(253)

elemSpace = wavelen / 2;  % half-wavelength spacing
numElem = [4 4];          % number of array elements
pwrSource = 1;            % source signal power
E = referenceEllipsoid('sphere');

usrLla = [[37.78, 36.59, 0]',[37.58, 37.51, 0]'];
usrLla = usrLla(:,1:numUsr);
data = [2026, 03, 12, 08, 53, 0];
utc = datetime(data);
tle = tleread("./tle/starlink_20260312.tle");
arrUpa = createUpa(numElem, elemSpace);
%%
%[text] ## Multi-Satellite Scene
% satellite scene
scene = genMultiSatScene(utc, tle, usrLla, [], [], arrUpa);
linkParam = getLinkParam(scene, wavelen);
steeringInfo = getSceneSteering(scene, wavelen);
%%
%[text] ## Signal Generation
snrDb = -20:3:10;
numParam = numel(snrDb);
numRepeat = 200;

latTrue = usrLla(1,1);
lonTrue = usrLla(2,1);
fdTrue = linkParam.ref.fdGeom(1);

mseLatDoaSingle = zeros(numParam, 1);
mseLonDoaSingle = zeros(numParam, 1);
mseLatDoaJoint  = zeros(numParam, 1);
mseLonDoaJoint  = zeros(numParam, 1);

mseLatDdSingle = zeros(numParam, 1);
mseLonDdSingle = zeros(numParam, 1);
mseFdDdSingle  = zeros(numParam, 1);
mseLatDdJoint  = zeros(numParam, 1);
mseLonDdJoint  = zeros(numParam, 1);
mseFdDdJoint   = zeros(numParam, 1);

crbDoaAz = zeros(numParam, 1);
crbDoaEl = zeros(numParam, 1);

crbDDLat = zeros(numParam, 1);
crbDDLon = zeros(numParam, 1);
crbDDFd  = zeros(numParam, 1);

% s-t music
doaGrid1 = genDoaGrid("latlon", 2, [50 50], [usrLla(1)-5, usrLla(1)+5; usrLla(2)-5, usrLla(2)+5], 'eci', datevec(utc), scene.satPosEci(:,1), scene.rotMat{1}, E);
doaGrid2 = genDoaGrid("latlon", 2, [50 50], [usrLla(1)-5, usrLla(1)+5; usrLla(2)-5, usrLla(2)+5], 'eci', datevec(utc), scene.satPosEci(:,2), scene.rotMat{2}, E);
fdRange = [0 2e5];

[pilotSym, pilotInfo] = genPilotSymbol(numUsr, numSym, 'pn', pwrSource);

% pulse shaping
pulseOpt = struct();
pulseOpt.rolloff = 0.25;
pulseOpt.span = 8;

[pilotWave, waveInfo] = genPilotWaveform(pilotSym, symbolRate, osf, 'rrc', pulseOpt);

% rx signal generation
modelOpt = struct();
modelOpt.delayMode = 'phaseonly';
modelOpt.carrierPhaseMode = 'none';

% 单星 scene
scene1 = localSelectSatScene(scene, 1);
scene2 = localSelectSatScene(scene, 2);

progressbar('reset', numParam);

for ii = 1:numParam %[output:group:773a0db1]
  pwrNoise = pwrSource / (10^(snrDb(ii) / 10));

  seLatDoaSingle = zeros(numRepeat, 1);
  seLonDoaSingle = zeros(numRepeat, 1);
  seLatDoaJoint  = zeros(numRepeat, 1);
  seLonDoaJoint  = zeros(numRepeat, 1);

  seLatDdSingle = zeros(numRepeat, 1);
  seLonDdSingle = zeros(numRepeat, 1);
  seFdDdSingle  = zeros(numRepeat, 1);
  seLatDdJoint  = zeros(numRepeat, 1);
  seLonDdJoint  = zeros(numRepeat, 1);
  seFdDdJoint   = zeros(numRepeat, 1);

  parfor rr = 1:numRepeat
    [rxSig, ~, ~, ~, ~] = genMultiSatSnapshots( ...
      steeringInfo, pilotWave, linkParam, carrierFreq, sampleRate, ...
      pwrNoise, 1, modelOpt);

    % ------------------------------------------------------------
    % DoA-only MLE
    % 注意：如果 rxSig 里含 Doppler，那么这个估计器存在模型失配
    % ------------------------------------------------------------
    estDoa1 = estimatorDoaMlePilotOpt(scene.array{1}, ...
      wavelen, rxSig{1}, pilotWave, doaGrid1);

    estDoaJ = estimatorDoaMlePilotOpt(scene.array, ...
      wavelen, rxSig, pilotWave, {doaGrid1, doaGrid2});

    latlonDoa1 = estDoa1.latlonEst(:,1);
    latlonDoaJ = estDoaJ.latlonEst(:,1);

    seLatDoaSingle(rr) = (latlonDoa1(1) - latTrue)^2;
    seLonDoaSingle(rr) = localWrapDeg(latlonDoa1(2) - lonTrue)^2;

    seLatDoaJoint(rr) = (latlonDoaJ(1) - latTrue)^2;
    seLonDoaJoint(rr) = localWrapDeg(latlonDoaJ(2) - lonTrue)^2;

    % ------------------------------------------------------------
    % Joint DoA-Doppler MLE
    % ------------------------------------------------------------
    estDd1 = estimatorDoaDopplerMlePilotOpt(scene1, ...
      rxSig{1}, pilotWave, carrierFreq, sampleRate, doaGrid1, fdRange);

    estDdJ = estimatorDoaDopplerMlePilotOpt(scene, ...
      rxSig, pilotWave, carrierFreq, sampleRate, ...
      {doaGrid1, doaGrid2}, fdRange);

    latlonDd1 = estDd1.latlonEst(:,1);
    latlonDdJ = estDdJ.latlonEst(:,1);

    fdDd1 = estDd1.fdRefEst(1);
    fdDdJ = estDdJ.fdRefEst(1);

    seLatDdSingle(rr) = (latlonDd1(1) - latTrue)^2;
    seLonDdSingle(rr) = localWrapDeg(latlonDd1(2) - lonTrue)^2;
    seFdDdSingle(rr)  = (fdDd1 - fdTrue)^2; 

    seLatDdJoint(rr) = (latlonDdJ(1) - latTrue)^2;
    seLonDdJoint(rr) = localWrapDeg(latlonDdJ(2) - lonTrue)^2;
    seFdDdJoint(rr)  = (fdDdJ - fdTrue)^2;
  end

  mseLatDoaSingle(ii) = mean(seLatDoaSingle);
  mseLonDoaSingle(ii) = mean(seLonDoaSingle);
  mseLatDoaJoint(ii)  = mean(seLatDoaJoint);
  mseLonDoaJoint(ii)  = mean(seLonDoaJoint);

  mseLatDdSingle(ii) = mean(seLatDdSingle);
  mseLonDdSingle(ii) = mean(seLonDdSingle);
  mseFdDdSingle(ii)  = mean(seFdDdSingle);
  mseLatDdJoint(ii)  = mean(seLatDdJoint);
  mseLonDdJoint(ii)  = mean(seLonDdJoint);
  mseFdDdJoint(ii)   = mean(seFdDdJoint);

  progressbar('advance'); %[output:3c26a1cb]
end %[output:group:773a0db1]
%%
for ii = 1:numParam
  pwrNoise = pwrSource / (10^(snrDb(ii) / 10));
  crbDD = crbPilotDoaDoppler(scene, pilotWave, carrierFreq, sampleRate, ...
    usrLla(1:2,1), fdTrue, 1, pwrNoise);

  crbDoa = crbDetDoa(scene1.array{1}, wavelen, scene1.localDoa, pwrSource, pwrNoise, length(pilotWave));

  crbDDLat(ii) = crbDD(1,1);
  crbDDLon(ii) = crbDD(2,2);
  crbDDFd(ii)  = crbDD(3,3);

  crbDoaAz(ii) = crbDoa(1,1);
  crbDoaEl(ii) = crbDoa(2,2);
end
%%
numSnap = length(pilotWave);

subplot(131); %[output:9b28e328]
semilogy( ... %[output:9b28e328]
  snrDb, mseLatDoaJoint, '-o', snrDb, mseLatDdJoint, '-o', ... %[output:9b28e328]
  snrDb, crbDoaAz, '-.', snrDb, crbDDLat, '-.'); %[output:9b28e328]
xlabel('SNR (dB)'); ylabel('MSE / rad^2'); grid on; %[output:9b28e328]
legend({'DoA only Est', 'DoA-Doppler Est', 'CRLB of DoA', 'CRLB of DoA-Doppler'}); %[output:9b28e328]
title(['Latitude (', num2str(numSnap), ' snaps)']); %[output:9b28e328]
% zp = BaseZoom();
% zp.run;

subplot(132); %[output:9b28e328]
semilogy( ... %[output:9b28e328]
  snrDb, mseLonDoaJoint, '-o', snrDb, mseLonDdJoint, '--o', snrDb, crbDDLon, '-.'); %[output:9b28e328]
xlabel('SNR (dB)'); ylabel('MSE / rad^2'); grid on; %[output:9b28e328]
legend({'DoA only Est', 'DoA-Doppler Est', 'CRLB'}); %[output:9b28e328]
title(['Longitude (', num2str(numSnap), ' snaps)']); %[output:9b28e328]
% zp = BaseZoom();
% zp.run;

subplot(133); %[output:9b28e328]
semilogy( ... %[output:9b28e328]
  snrDb, mseFdDdJoint, '-o', snrDb, crbDDFd, '-.'); %[output:9b28e328]
xlabel('SNR (dB)'); ylabel('MSE / rad^2'); grid on; %[output:9b28e328]
title(['Doppler (', num2str(numSnap), ' snaps)']); %[output:9b28e328]
legend({'DoA-Doppler Est', 'CRLB'}); %[output:9b28e328]
title(['Doppler (', num2str(numSnap), ' snaps)']); %[output:9b28e328]
% zp = BaseZoom();
% zp.run;
%%
% saveExpSnapshot("doaDopplerStatDualSatUraEciPerf");
%%
function errDeg = localWrapDeg(errDeg)
%LOCALWRAPDEG Wrap angle error to [-180, 180).
errDeg = mod(errDeg + 180, 360) - 180;
end

function sceneOut = localSelectSatScene(sceneIn, satIdx)
%LOCALSELECTSATSCENE Extract one-satellite scene from a multi-satellite scene.

sceneOut = sceneIn;
sceneOut.numSat = 1;
sceneOut.satPosEci = sceneIn.satPosEci(:, satIdx);
sceneOut.satVelEci = sceneIn.satVelEci(:, satIdx);
sceneOut.rotMat = sceneIn.rotMat(satIdx);
sceneOut.array = sceneIn.array(satIdx);

if isfield(sceneIn, 'localDoa')
  if ndims(sceneIn.localDoa) == 2
    sceneOut.localDoa = sceneIn.localDoa(:, satIdx);
  else
    sceneOut.localDoa = sceneIn.localDoa(:, satIdx, :);
  end
end
end

